// src/components/auth/LoginPage.jsx
import { useState } from "react";
import { Logo } from "../shared/index.jsx";
import { useAuth } from "../../hooks/useAuth";
import logoImg from "./logo.png";

export default function LoginPage() {
  const { login }         = useAuth();
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [role,     setRole]     = useState("intern");
  const [error,    setError]    = useState("");
  const [loading,  setLoading]  = useState(false);

  const handle = async () => {
    if (!username || !password) { setError("Please enter username and password."); return; }
    setLoading(true); setError("");
    try { await login(username, password, role); }
    catch (e) { setError(e.message || "Invalid credentials."); setLoading(false); }
  };

  return (
    <div style={{ minHeight:"100vh", display:"flex", alignItems:"center", justifyContent:"center", background:"linear-gradient(145deg,#051a0e 0%,#0a2e1a 40%,#155030 100%)", position:"relative", overflow:"hidden", padding:24 }}>
      <div style={{ position:"absolute", width:480, height:480, borderRadius:"50%", background:"radial-gradient(circle,rgba(46,204,122,.18),transparent 70%)", top:-100, right:-100, pointerEvents:"none" }}/>
      <div style={{ position:"absolute", width:360, height:360, borderRadius:"50%", background:"radial-gradient(circle,rgba(212,168,67,.12),transparent 70%)", bottom:-80, left:-80, pointerEvents:"none" }}/>

      <div className="animate-fadeUp" style={{ background:"rgba(255,255,255,.98)", borderRadius:26, padding:"48px 44px", width:440, maxWidth:"100%", boxShadow:"0 28px 90px rgba(0,0,0,.38)", position:"relative", zIndex:1 }}>
        {/* Logo */}
        <div style={{ textAlign:"center", marginBottom:28, display:"flex", flexDirection:"column", alignItems:"center", gap:-6 }}>
         <img src={logoImg} alt="Eco Green International" style={{ width:150, height:200, objectFit:"contain", borderRadius:16 }}/>
          <div style={{ fontFamily:"Syne,sans-serif", fontSize:25, fontWeight:900, color:"#0a2e1a", letterSpacing:".3px" }}>Eco Green International Pvt Ltd</div>
          <div style={{ fontSize:11, fontWeight:900,color:"#6b7280", letterSpacing:".8px", textTransform:"uppercase" }}>Intern Training Programme 2025 / 2026</div>
        </div>

        <h2 style={{ fontFamily:"Syne,sans-serif", fontSize:26, fontWeight:800, color:"#0a2e1a", textAlign:"center", marginBottom:6 }}>Welcome Back</h2>
        <p style={{ fontSize:13, color:"#6b7280", textAlign:"center", marginBottom:26 }}>Sign in to access your internship portal</p>

        {/* Role tabs */}
        <div style={{ display:"flex", gap:8, marginBottom:22 }}>
          {[{key:"intern",label:"👨‍💻  Intern"},{key:"supervisor",label:"👔  Supervisor"}].map(r=>(
            <button key={r.key} onClick={()=>{setRole(r.key);setError("");}}
              style={{ flex:1, padding:"10px 8px", borderRadius:9, border:`2px solid ${role===r.key?"#2ecc7a":"#e5e7eb"}`, background:role===r.key?"#f3fdf7":"white", cursor:"pointer", fontSize:13, fontWeight:600, fontFamily:"inherit", transition:"all .2s", color:role===r.key?"#155030":"#6b7280" }}>
              {r.label}
            </button>
          ))}
        </div>

        {error && <div className="alert alert-error mb-16" style={{marginBottom:14}}>⚠️ {error}</div>}

        <div className="form-group">
          <label className="form-label">Username</label>
          <input className="form-input" value={username} onChange={e=>setUsername(e.target.value)} placeholder="Enter your username" onKeyDown={e=>e.key==="Enter"&&handle()} autoFocus/>
        </div>
        <div className="form-group">
          <label className="form-label">Password</label>
          <input className="form-input" type="password" value={password} onChange={e=>setPassword(e.target.value)} placeholder="Enter your password" onKeyDown={e=>e.key==="Enter"&&handle()}/>
        </div>

        <button className="btn btn-primary btn-lg w-full" onClick={handle} disabled={loading} style={{marginTop:8, justifyContent:"center"}}>
          {loading?"Signing in…":"Sign In →"}
        </button>


      </div>
    </div>
  );
}
